<?php
$search = sanitize_text_field( wp_unslash( $_GET['s'] ?? '' ) ); $paged = max( 1, absint( $_GET['pg'] ?? 1 ) ); $limit = 20; $offset = ( $paged - 1 ) * $limit; $like = '%' . $wpdb->esc_like( $search ) . '%';
$where = $search ? $wpdb->prepare( 'WHERE first_name LIKE %s OR last_name LIKE %s OR phone LIKE %s OR email LIKE %s OR national_id LIKE %s', $like, $like, $like, $like, $like ) : '';
$rows = $wpdb->get_results( "SELECT * FROM {$wpdb->prefix}ct_clients $where ORDER BY updated_at DESC LIMIT $limit OFFSET $offset" );
?><div class="ct-titlebar"><div><h1>Clients</h1><div class="ct-muted">Borrowers, contacts, and protected documents.</div></div><?php if ( current_user_can( 'creditrack_manage_clients' ) ) { ?><a class="ct-button" href="#client-form">Add client</a><?php } ?></div>
<form class="ct-toolbar" method="get"><label for="client-search">Search clients</label><input id="client-search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="Name, phone, email, or national ID"><button>Search</button></form>
<div class="ct-table-wrap"><table><thead><tr><th>Name</th><th>Phone</th><th>Email</th><th>National ID</th><th>Status</th></tr></thead><tbody><?php foreach ( $rows as $row ) { ?><tr><td><a href="<?php echo esc_url( add_query_arg( 'client_id', $row->id, $base . 'clients/' ) ); ?>"><?php echo esc_html( "$row->first_name $row->last_name" ); ?></a></td><td><?php echo esc_html( $row->phone ); ?></td><td><?php echo esc_html( $row->email ); ?></td><td><?php echo esc_html( $row->national_id ); ?></td><td><span class="ct-badge"><?php echo $row->is_active ? 'Active' : 'Inactive'; ?></span></td></tr><?php } if ( ! $rows ) { ?><tr><td colspan="5">No clients match this search.</td></tr><?php } ?></tbody></table></div>
<?php $selected_client = absint( $_GET['client_id'] ?? 0 ); if ( $selected_client ) { $client = $wpdb->get_row( $wpdb->prepare( "SELECT first_name,last_name FROM {$wpdb->prefix}ct_clients WHERE id=%d", $selected_client ) ); $documents = $wpdb->get_results( $wpdb->prepare( "SELECT * FROM {$wpdb->prefix}ct_client_documents WHERE client_id=%d ORDER BY uploaded_at DESC", $selected_client ) ); if ( $client ) { ?><section class="ct-card"><h2>Protected documents — <?php echo esc_html( "$client->first_name $client->last_name" ); ?></h2><div class="ct-table-wrap"><table><thead><tr><th>Type</th><th>Filename</th><th>Size</th><th>Uploaded</th><th>Actions</th></tr></thead><tbody><?php foreach ( $documents as $document ) { $download = wp_nonce_url( add_query_arg( array( 'action' => 'creditrack_download_document', 'document_id' => $document->id ), admin_url( 'admin-post.php' ) ), 'creditrack_download_document' ); ?><tr><td><?php echo esc_html( $document->document_type ); ?></td><td><?php echo esc_html( $document->original_name ); ?></td><td><?php echo esc_html( size_format( $document->file_size ) ); ?></td><td><?php echo esc_html( $document->uploaded_at ); ?></td><td><div class="ct-actions"><a class="ct-button secondary" href="<?php echo esc_url( $download ); ?>">Download</a><?php if ( current_user_can( 'creditrack_manage_documents' ) ) { ?><form method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_delete_document"><input type="hidden" name="client_id" value="<?php echo esc_attr( $selected_client ); ?>"><input type="hidden" name="document_id" value="<?php echo esc_attr( $document->id ); ?>"><button class="ct-danger-button" type="submit" data-confirm="Delete this protected document?">Delete</button></form><?php } ?></div></td></tr><?php } if ( ! $documents ) { ?><tr><td colspan="5">No documents uploaded.</td></tr><?php } ?></tbody></table></div><?php if ( current_user_can( 'creditrack_manage_documents' ) ) { ?><form class="ct-form ct-subform" method="post" enctype="multipart/form-data" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_upload_document"><input type="hidden" name="client_id" value="<?php echo esc_attr( $selected_client ); ?>"><div class="ct-field"><label for="document_type">Document type</label><select id="document_type" name="document_type"><?php foreach ( array( 'National ID','Proof of Address','Proof of Income','Collateral Document','Other' ) as $type ) { ?><option><?php echo esc_html( $type ); ?></option><?php } ?></select></div><div class="ct-field"><label for="document">PDF, JPEG, or PNG</label><input id="document" type="file" name="document" accept="application/pdf,image/jpeg,image/png" required></div><div class="ct-field full"><button type="submit">Upload protected document</button></div></form><?php } ?></section><?php } }
if ( current_user_can( 'creditrack_manage_clients' ) ) { ?><section id="client-form" class="ct-card"><h2>Add client</h2><form class="ct-form" method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_save_client"><?php foreach ( array( 'first_name'=>'First name','last_name'=>'Last name','email'=>'Email','phone'=>'Phone','national_id'=>'National ID','occupation'=>'Occupation','monthly_income'=>'Monthly income','next_of_kin_name'=>'Next-of-kin name','next_of_kin_phone'=>'Next-of-kin phone' ) as $name => $label ) { ?><div class="ct-field"><label for="<?php echo esc_attr( $name ); ?>"><?php echo esc_html( $label ); ?></label><input id="<?php echo esc_attr( $name ); ?>" name="<?php echo esc_attr( $name ); ?>" <?php echo in_array( $name, array( 'first_name','last_name','phone' ), true ) ? 'required' : ''; ?>></div><?php } ?><div class="ct-field full"><label for="address">Address</label><textarea id="address" name="address" required></textarea></div><div class="ct-field full"><label for="next_of_kin_address">Next-of-kin address</label><textarea id="next_of_kin_address" name="next_of_kin_address"></textarea></div><div class="ct-field full"><label for="notes">Notes</label><textarea id="notes" name="notes"></textarea></div><div><button type="submit">Save client</button></div></form></section><?php }
